3_real_world_example.code:
const button1 = document.getElementById('btn1');
const button2 = document.getElementById('btn2');

// We want to store how many times each button was clicked.
const clickCounts = new Map();

// Using the HTML Element OBJECT ITSELF as the dictionary key!
clickCounts.set(button1, 0);
clickCounts.set(button2, 0);

button1.addEventListener('click', () => {
  const current = clickCounts.get(button1);
  clickCounts.set(button1, current + 1);
  console.log('Button 1 clicks:', clickCounts.get(button1));
});

